const items = $input.first().json.checkouts || [];
const now = new Date();
return items.flatMap(c => {
  const hours = (now - new Date(c.updated_at)) / 3.6e6;
  let stage = null, cupom = null;
  if (hours >= 22 && hours <= 26)  { stage = 'D+1'; cupom = 'AURA10'; }
  else if (hours >= 70 && hours <= 74) { stage = 'D+3'; cupom = 'AURAVIP15'; }
  else if (hours >= 166 && hours <= 170) { stage = 'D+7'; cupom = 'AURAEMBAIXADORA20'; }
  if (!stage) return [];
  return [{ json: { email: c.email, total: c.total_price, stage, cupom, items: c.line_items?.map(i => i.title).join(', ') || '' } }];
});
